  ('social-worker-moex-05820', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列關於社區總體營造的敘述，何者錯誤？', '["對象是「有改變、追求幸福意願的社區」", "只要居民願意參與即可", "主張人與環境改變並重", "外部資源性質包含專業人力與財務資源"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05821', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', 'Rowe與Frewer（2000）提出多種社區參與方式：「只限於有興趣的市民，參與的人數有限，真正參與且 有決策權的為專業者及政治菁英」，請問這是屬於下列那一種社區參與方式？', '["市民審議/小組", "市民諮議委員會", "公聽會/諮詢", "公議會"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05822', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列對社區工作的敘述，何者正確？①是一種以社區為對象的社會工作介入方法  ②社區工作最重要的', '["目標之一是提升居民的社區意識", "社區工作做的就是弱勢者的社會福利  ⑤社區總體營造 也可視為是一種社區工作", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 40, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05823', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'essay', '現代研究都很重視科學方法的運用，科學方法的主要特性包括有暫時性
（tentative）、反覆論證性（replication）、觀察（observation）、無偏見（unbiased）
及透明化（transparent）。請說明上述 5 項特性及為什麼科學方法需要重視這 5 項
特性。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05824', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'essay', '當研究人員想確定一項事物是否成為造成另項事物的原因時，實驗設計
（experimental design）被認為是最好的方法之一，其中有一種比較精緻的實驗設計
為所羅門四組設計（Solomon four-group design）。若你是老人日間照顧中心的社工人
員，請你以所羅門四組設計方式說明日間照顧對老人身體機能是否有助益。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05825', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關演繹（deduction）與歸納（induction）的敘述，何者錯誤？', '["個案解釋（idiographic）是一種歸納推論，通則解釋（nomothetic）則是演繹推論", "演繹始於一個預期模式，這個模式由觀察來加以檢驗", "歸納始於觀察，並試圖尋找其中模式", "理論和研究的互動是透過歸納與演繹永無止境的交替過程"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05826', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '通則因果關係的判準，不包括下列那一項？', '["原因具有信度與效度", "原因出現的時間先於結果", "結果不能被某第三變項所解釋", "變項間必須是有相關"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05827', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關測量（衡量）尺度（measurement scale）的敘述，何者錯誤？', '["等比資料有固定原點（絕對零點），這是指當資料的數值為0時，代表「有」的意思", "資料的衡量尺度是給予資料一個實數值，作為比較或計算的基礎", "變項「小孩數」，屬於等比尺度（ratio scale）", "等比資料數值之差距具有大小的意義"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05828', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關「概念化」與「操作化」，請問下列敘述何者錯誤？', '["操作化就是對於我們所指的概念，具體說明其特定測量方法", "概念化就是對於我們所指的事物，賦予明確意義之過程", "透過操作化，研究者將腦中抽象的想法（概念）和真實世界中具體的指標加以連結", "概念和測量操作間的連結過程，被稱為概念化"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05829', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關「理論、命題、概念、假設」的敘述，何者錯誤？', '["概念：具體說明測量變項所需的確切操作方式", "假設：陳述兩個（或更多）變項之間的預期因果關係", "理論：系統化的一組相關聯之陳述，用以解釋某些層面的社會生活", "命題（propositions）：以公理為基礎所導出的特定結論，敘述概念之間的關係"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
